import path from"node:path";import{BrowserPlatform}from"./types.js";function folder(r){switch(r){case BrowserPlatform.LINUX_ARM:case BrowserPlatform.LINUX:return"linux64";case BrowserPlatform.MAC_ARM:return"mac-arm64";case BrowserPlatform.MAC:return"mac-x64";case BrowserPlatform.WIN32:return"win32";case BrowserPlatform.WIN64:return"win64"}}export function resolveDownloadUrl(r,e,o="https://storage.googleapis.com/chrome-for-testing-public"){return`${o}/${resolveDownloadPath(r,e).join("/")}`}export function resolveDownloadPath(r,e){return[e,folder(r),`chromedriver-${folder(r)}.zip`]}export function relativeExecutablePath(r,e){switch(r){case BrowserPlatform.MAC:case BrowserPlatform.MAC_ARM:return path.join("chromedriver-"+folder(r),"chromedriver");case BrowserPlatform.LINUX_ARM:case BrowserPlatform.LINUX:return path.join("chromedriver-linux64","chromedriver");case BrowserPlatform.WIN32:case BrowserPlatform.WIN64:return path.join("chromedriver-"+folder(r),"chromedriver.exe")}}export{resolveBuildId,compareVersions}from"./chrome.js";